sys_script.script:
(function executeRule(current, previous) {

    // Only fire when state transitions into Degraded or Outage
    if (previous && previous.u_state.toString() === current.u_state.toString()) {
        return;
    }

    var creator = new ProactiveIncidentCreator();
    creator.createForAnomalyEvent(current);

})(current, previous);
